sql:
SELECT year, MAX(life_expectancy) AS max_life_expectancy, MIN(life_expectancy) AS min_life_expectancy
FROM life_expectancy
GROUP BY year;

SELECT country_name
FROM countries
WHERE country_id IN (0, 1);

SELECT country_name
FROM countries
WHERE gdp_per_capita > (SELECT AVG(gdp_per_capita) FROM countries);

SELECT year, life_expectancy
FROM life_expectancy
WHERE year = 2022;

