SELECT country_name
FROM (
  SELECT country_name, CUME_DIST() OVER (ORDER BY gdp DESC) as cume_dist
  FROM countries
) subquery
WHERE cume_dist <= 0.5;

SELECT country_name 
FROM countries 
WHERE population > (SELECT AVG(population) FROM countries);
